class Solution(object):
    def romanToInt(self, s):
        roman_map = {'I':1,'V':5,'X':10,'L':50,'C':100,'D':500,'M':1000}
        result = 0
        for i in range(len(s)-1, -1, -1):
            value = roman_map[s[i]]
            if i < len(s) - 1 and value < roman_map[s[i+1]]:
                result -= value
            else:
                result += value
        return result
